/**
 * HRSA shortage area data lookup.
 * The bundled JSON (public/hrsa-shortage.json) is keyed by 5-digit county FIPS code.
 *
 * Each county record contains:
 *   pc:  { score, status, name } | null  — Primary Care HPSA
 *   dh:  { score, status, name } | null  — Dental Health HPSA
 *   mh:  { score, status, name } | null  — Mental Health HPSA
 *   mua: { imu_score, status, name } | null  — Medically Underserved Area
 *   mup: { imu_score, status, name } | null  — Medically Underserved Population
 *
 * The data file is generated by scripts/process-hrsa-data.mjs
 * Run: npm run data:hrsa
 */

let hrsaData = null;
let loadPromise = null;

async function loadHrsaData() {
  if (hrsaData) return hrsaData;
  if (loadPromise) return loadPromise;

  loadPromise = fetch("/hrsa-shortage.json")
    .then(r => {
      if (!r.ok) throw new Error(`Failed to load HRSA shortage data: HTTP ${r.status}`);
      return r.json();
    })
    .then(data => {
      hrsaData = data;
      return data;
    })
    .catch(e => {
      // Non-fatal — app works without HRSA data
      console.warn("HRSA data not available:", e.message);
      hrsaData = { _meta: { vintage: "", generated: "", hpsa_counties_with_designation: 0, mua_counties_with_designation: 0 } };
      return hrsaData;
    });

  return loadPromise;
}

/**
 * Look up HRSA shortage data by county FIPS.
 * @param {string} stateCode  2-digit state FIPS (e.g. "22")
 * @param {string} countyCode 3-digit county FIPS within state (e.g. "071")
 * @returns {object|null} county record or null if no designation / data not loaded
 */
export function lookupHrsaByCounty(stateCode, countyCode) {
  if (!hrsaData) return null;
  const fips5 = `${stateCode}${countyCode}`.padStart(5, "0").slice(0, 5);
  return hrsaData[fips5] ?? null;
}

/**
 * Look up HRSA shortage data directly by 5-digit county FIPS.
 * Useful when deriving county FIPS from a GEOID (first 5 digits).
 */
export function lookupHrsaByFips5(fips5) {
  if (!hrsaData) return null;
  return hrsaData[String(fips5).padStart(5, "0")] ?? null;
}

/** Returns true if the data file has been populated (i.e. contains real records). */
export function isHrsaDataPopulated() {
  if (!hrsaData) return false;
  return (hrsaData._meta?.hpsa_counties_with_designation ?? 0) > 0 ||
         (hrsaData._meta?.mua_counties_with_designation  ?? 0) > 0;
}

/** Returns the vintage string from the data file metadata. */
export function getHrsaVintage() {
  return hrsaData?._meta?.vintage ?? null;
}

/** Call at app startup to preload the data in the background. */
export async function preloadHrsaData() {
  return loadHrsaData();
}
